 1	import React, { FC } from 'react';
 2	import xbytes from 'xbytes';
 3	
 4	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import SubTitleChartLabel from '@kubevirt-utils/components/Charts/ChartLabels/SubTitleChartLabel';
 6	import TitleChartLabel from '@kubevirt-utils/components/Charts/ChartLabels/TitleChartLabel';
 7	import ComponentReady from '@kubevirt-utils/components/Charts/ComponentReady/ComponentReady';
 8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 9	import { useGuestOS } from '@kubevirt-utils/resources/vmi';
10	import { removeDuplicatesByName } from '@kubevirt-utils/utils/utils';
11	import { ChartDonutUtilization } from '@patternfly/react-charts';
12	
13	type StorageUtilProps = {
14	  vmi: V1VirtualMachineInstance;
15	};
16	
17	const StorageUtil: FC<StorageUtilProps> = ({ vmi }) => {
18	  const { t } = useKubevirtTranslation();
19	
20	  const [guestAgentData, loaded] = useGuestOS(vmi);
21	
22	  const { totalBytes = 0, usedBytes = 0 } =
23	    removeDuplicatesByName(guestAgentData?.fsInfo?.disks, 'diskName')?.reduce(
24	      (acc, data) => {
25	        acc.totalBytes += data?.totalBytes;
26	        acc.usedBytes += data?.usedBytes;
27	        return acc;
28	      },
29	      { totalBytes: 0, usedBytes: 0 },
30	    ) || {};
31	
32	  const usedPercentage = (usedBytes / totalBytes) * 100 || 0;
33	
34	  const isReady = !Number.isNaN(usedPercentage) && loaded;
35	
36	  return (
37	    <div className="util">
38	      <div className="util-upper">
39	        <div className="util-title">{t('Storage')}</div>
40	        <div className="util-summary" data-test-id="util-summary-storage">
41	          <div className="util-summary-value">
42	            {xbytes(usedBytes || 0, { fixed: 2, iec: true })}
43	          </div>
44	          <div className="util-summary-text text-muted">
45	            <div>{t('Used of ')}</div>
46	            <div>{xbytes(totalBytes || 0, { fixed: 2, iec: true })}</div>
47	          </div>
48	        </div>
49	      </div>
50	      <div className="util-chart">
51	        <ComponentReady isReady={isReady}>
52	          <ChartDonutUtilization
53	            data={{
54	              x: t('Storage used'),
55	              y: usedPercentage,
56	            }}
57	            labels={({ datum }) =>
58	              datum.x ? `${datum.x}: ${xbytes(usedBytes || 0, { fixed: 2, iec: true })}` : null
59	            }
60	            animate
61	            constrainToVisibleArea
62	            style={{ labels: { fontSize: 20 } }}
63	            subTitle={t('Used')}
64	            subTitleComponent={<SubTitleChartLabel y={135} />}
65	            title={`${usedPercentage.toFixed(2) || 0}%`}
66	            titleComponent={<TitleChartLabel />}
67	          />
68	        </ComponentReady>
69	      </div>
70	    </div>
71	  );
72	};
73	
74	export default StorageUtil;

